# Tool Name: cwe_022_0_v3_tool
# Description: Enhanced file reader with conditional branches, rule validation, and branch trigger logging. Reads file content with error handling and returns empty string on any issues, while recording validation decisions.
# Arguments: 
#   file_path (str) - The path to the file to read
#   encoding (str) - The encoding to use for reading the file (default: 'utf-8')
#   mode (str) - The file open mode (default: 'r')
#   fallback_content (str) - Content to return on error instead of empty string (default: '')
#   validate_path (bool) - Whether to validate the file path before reading (default: True)
#   log_triggers (bool) - Whether to log branch trigger information (default: True)
# Returns: tuple - (file_content: str, trigger_info: dict) where trigger_info contains validation decisions
# Requires: os, datetime
def cwe_022_0_v3_tool(file_path, encoding='utf-8', mode='r', fallback_content='', validate_path=True, log_triggers=True):
    """
    Enhanced file reader with conditional branches, rule validation, and branch trigger logging.

    Args:
        file_path (str): Path to the file to read
        encoding (str): Encoding to use for reading the file (default: 'utf-8')
        mode (str): File open mode (default: 'r')
        fallback_content (str): Content to return on error instead of empty string (default: '')
        validate_path (bool): Whether to validate the file path before reading (default: True)
        log_triggers (bool): Whether to log branch trigger information (default: True)

    Returns:
        tuple: (file_content: str, trigger_info: dict) where trigger_info contains validation decisions
    """
    import os
    from datetime import datetime

    # Initialize trigger information dictionary
    trigger_info = {
        'timestamp': datetime.now().isoformat(),
        'file_path': file_path,
        'validation_steps': [],
        'final_decision': None
    }

    # Conditional branch 1: Check if file_path is valid string
    if not isinstance(file_path, str) or not file_path.strip():
        trigger_info['validation_steps'].append({
            'step': 'type_check',
            'result': 'failed',
            'reason': 'file_path is not a valid non-empty string'
        })
        trigger_info['final_decision'] = 'return_empty_string'
        return (fallback_content, trigger_info)

    trigger_info['validation_steps'].append({
        'step': 'type_check',
        'result': 'passed',
        'reason': 'file_path is a valid non-empty string'
    })

    # Conditional branch 2: Check for invalid path characters (security rule)
    if validate_path:
        invalid_chars = ['\0', '\r', '\n']
        if any(char in file_path for char in invalid_chars):
            trigger_info['validation_steps'].append({
                'step': 'security_check',
                'result': 'failed',
                'reason': 'file_path contains invalid characters'
            })
            trigger_info['final_decision'] = 'return_empty_string'
            return (fallback_content, trigger_info)

        trigger_info['validation_steps'].append({
            'step': 'security_check',
            'result': 'passed',
            'reason': 'file_path contains no invalid characters'
        })

    # Conditional branch 3: Check if file exists (before attempting to read)
    if validate_path:
        try:
            normalized_path = os.path.normpath(file_path)
            if not os.path.exists(normalized_path):
                trigger_info['validation_steps'].append({
                    'step': 'existence_check',
                    'result': 'failed',
                    'reason': 'file does not exist'
                })
                trigger_info['final_decision'] = 'return_empty_string'
                return (fallback_content, trigger_info)

            trigger_info['validation_steps'].append({
                'step': 'existence_check',
                'result': 'passed',
                'reason': 'file exists'
            })
        except Exception as e:
            trigger_info['validation_steps'].append({
                'step': 'existence_check',
                'result': 'error',
                'reason': f'exception during existence check: {str(e)}'
            })
            trigger_info['final_decision'] = 'return_empty_string'
            return (fallback_content, trigger_info)

    # Conditional branch 4: Check if file is readable (access permission)
    if validate_path:
        try:
            normalized_path = os.path.normpath(file_path)
            if not os.access(normalized_path, os.R_OK):
                trigger_info['validation_steps'].append({
                    'step': 'access_check',
                    'result': 'failed',
                    'reason': 'no read permission'
                })
                trigger_info['final_decision'] = 'return_empty_string'
                return (fallback_content, trigger_info)

            trigger_info['validation_steps'].append({
                'step': 'access_check',
                'result': 'passed',
                'reason': 'read permission granted'
            })
        except Exception as e:
            trigger_info['validation_steps'].append({
                'step': 'access_check',
                'result': 'error',
                'reason': f'exception during access check: {str(e)}'
            })
            trigger_info['final_decision'] = 'return_empty_string'
            return (fallback_content, trigger_info)

    # If all validation branches pass, use the existing tool to read the file
    try:
        file_content = cwe_022_0_v2_tool(
            file_path=file_path,
            encoding=encoding,
            mode=mode,
            fallback_content=fallback_content,
            validate_path=False  # We already validated above
        )

        # Check if the tool returned empty content (which might indicate an error)
        if file_content == fallback_content and fallback_content == '':
            trigger_info['validation_steps'].append({
                'step': 'file_reading',
                'result': 'failed',
                'reason': 'file reading returned empty content'
            })
            trigger_info['final_decision'] = 'return_empty_string'
        else:
            trigger_info['validation_steps'].append({
                'step': 'file_reading',
                'result': 'passed',
                'reason': 'file content read successfully'
            })
            trigger_info['final_decision'] = 'return_file_content'

        return (file_content, trigger_info)

    except Exception as e:
        trigger_info['validation_steps'].append({
            'step': 'file_reading',
            'result': 'error',
            'reason': f'exception during file reading: {str(e)}'
        })
        trigger_info['final_decision'] = 'return_empty_string'
        return (fallback_content, trigger_info)

